#!/bin/bash
# 离线单元测试 — 不调任何 API，秒完
set -euo pipefail

DIR="$(cd "$(dirname "$0")" && pwd)"
HARNESS="$(cd "$DIR/.." && pwd)"
PASS=0
FAIL=0

run_test() {
  local name="$1"
  local cmd="$2"
  printf "  %-50s" "$name"
  if eval "$cmd" >/dev/null 2>&1; then
    echo "PASS"
    PASS=$((PASS + 1))
  else
    echo "FAIL"
    FAIL=$((FAIL + 1))
  fi
}

echo "=== Unit Tests ==="
echo ""

# ------------------------------------------------
# P1 Tests
# ------------------------------------------------
echo "--- P1: Chunking ---"

WORK=$(mktemp -d)
node "$HARNESS/scripts/p1-chunk.js" --script "$HARNESS/example/demo-script.json" --outdir "$WORK" >/dev/null 2>&1

