run_test() {
  local name="$1"
  local cmd="$2"
  printf "  %-50s" "$name"
  if eval "$cmd" >/dev/null 2>&1; then
    echo "PASS"
    PASS=$((PASS + 1))
  else
    echo "FAIL"
    FAIL=$((FAIL + 1))
  fi
}

